// Extract JSON from agent response
const agentResponse = $input.first().json.output;

// Try to extract JSON from the response text
let invoiceData;

try {
  // Look for JSON in the response
  const jsonMatch = agentResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    invoiceData = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error("No JSON found in response");
  }
} catch (error) {
  // Fallback: try to parse the entire response as JSON
  try {
    invoiceData = JSON.parse(agentResponse);
  } catch (parseError) {
    throw new Error(`Failed to parse JSON from agent response: ${parseError.message}`);
  }
}

// Validate required fields
const requiredFields = ['lift_ticket', 'file_id', 'vendor_name', 'invoice_number', 'total_amount'];
for (const field of requiredFields) {
  if (!invoiceData[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Ensure action is valid
if (!['approve', 'reject', 'pending'].includes(invoiceData.action)) {
  invoiceData.action = 'pending';
}

// Add rejection_reason if action is reject but no reason provided
if (invoiceData.action === 'reject' && !invoiceData.rejection_reason) {
  invoiceData.rejection_reason = 'Rejected by business rules';
}

return [{
  json: invoiceData
}];
